const EXT_KEY = 'runnore_acrylic_enabled';
let isAcrylicEnabled = localStorage.getItem(EXT_KEY) !== 'false';

function applyAcrylicTheme() {
    let style = document.getElementById('acrylic-styles');
    if (!style) {
        style = document.createElement('style');
        style.id = 'acrylic-styles';
        document.head.appendChild(style);
    }

    if (isAcrylicEnabled) {
        style.innerHTML = 
            "#app-container { background: rgba(15, 15, 15, 0.45) !important; }" +
            "[data-theme='light'] #app-container { background: rgba(240, 240, 240, 0.45) !important; }" +
            ".panel-container, #sidebar, #titlebar, .search-dropdown {" +
            "    background: rgba(20, 20, 20, 0.35) !important;" +
            "    backdrop-filter: blur(16px); -webkit-backdrop-filter: blur(16px);" +
            "    border-color: rgba(255, 255, 255, 0.08) !important;" +
            "}" +
            "[data-theme='light'] .panel-container, [data-theme='light'] #sidebar, [data-theme='light'] #titlebar {" +
            "    background: rgba(255, 255, 255, 0.4) !important;" +
            "    border-color: rgba(0, 0, 0, 0.08) !important;" +
            "}" +
            ".console-toolbar, .explorer-header, .settings-nav, #tabs-bar {" +
            "    background: rgba(25, 25, 25, 0.4) !important;" +
            "}" +
            "[data-theme='light'] .console-toolbar, [data-theme='light'] .explorer-header, [data-theme='light'] .settings-nav, [data-theme='light'] #tabs-bar {" +
            "    background: rgba(250, 250, 250, 0.4) !important;" +
            "}" +
            "#editor-area { background: transparent !important; }" +
            ".monaco-editor, .monaco-editor-background, .monaco-editor .margin { background-color: transparent !important; }";

        if (window.editor && window.monaco) {
            monaco.editor.defineTheme('acrylic-dark', {
                base: 'vs-dark',
                inherit: true,
                rules: [
                    { token: 'keyword', foreground: 'ff7b72', fontStyle: 'bold' },
                    { token: 'string', foreground: 'a5d6ff' },
                    { token: 'number', foreground: '79c0ff' },
                    { token: 'comment', foreground: '8b949e', fontStyle: 'italic' },
                    { token: 'identifier', foreground: 'd2a8ff' },
                ],
                colors: {
                    'editor.background': '#00000000',
                    'editor.lineHighlightBackground': '#ffffff10',
                    'editorLineNumber.foreground': '#6e7681'
                }
            });

            const isLight = document.documentElement.getAttribute('data-theme') === 'light';
            if(!isLight) monaco.editor.setTheme('acrylic-dark');
        }
    } else {
        style.innerHTML = '';
        if (window.editor && window.monaco) {
            const isLight = document.documentElement.getAttribute('data-theme') === 'light';
            monaco.editor.setTheme(isLight ? 'runnore-theme-light' : 'runnore-theme');
        }
    }
}

function setupSettingsToggle() {
    const extSettingsContainer = document.getElementById('settings-extensions');
    if (!extSettingsContainer) return;

    if (!document.getElementById('row-acrylic-glass')) {
        const row = document.createElement('div');
        row.className = 'setting-row';
        row.id = 'row-acrylic-glass';

        const infoDiv = document.createElement('div');
        infoDiv.className = 'setting-info';
        infoDiv.innerHTML = '<h4>Acrylic Glass 11</h4><p>Enable semi-transparent panels and high-contrast syntax highlighting.</p>';

        const toggleDiv = document.createElement('div');
        toggleDiv.className = 'toggle-switch' + (isAcrylicEnabled ? ' on' : '');
        toggleDiv.id = 'toggle-acrylic';

        row.appendChild(infoDiv);
        row.appendChild(toggleDiv);
        extSettingsContainer.appendChild(row);

        toggleDiv.onclick = function() {
            isAcrylicEnabled = !isAcrylicEnabled;
            this.classList.toggle('on', isAcrylicEnabled);
            localStorage.setItem(EXT_KEY, isAcrylicEnabled);
            applyAcrylicTheme();
        };
    }
}

const checkMonaco = setInterval(() => {
    if (window.editor && window.monaco) {
        clearInterval(checkMonaco);
        applyAcrylicTheme();
    }
}, 500);

applyAcrylicTheme();
setTimeout(setupSettingsToggle, 500);

const themeBtn = document.getElementById('theme-toggle');
if (themeBtn) {
    themeBtn.addEventListener('click', () => {
        setTimeout(applyAcrylicTheme, 50);
    });
}
